queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?jazz_bands a :Jazz_Bands .
    ?jazz_bands p:Band ?band .
    BIND(?band AS ?o0)
  }
  UNION
  {
    ?rock_bands a :Rock_Bands .
    ?rock_bands p:Band ?band .
    ?rock_bands p:Founding_Year ?founding_year_f .
    FILTER((STR(?founding_year_f) = "1970" || STR(?founding_year_f) = "1970.0"))
    BIND(?band AS ?o0)
  }
}

